import React, { useEffect, useState } from 'react';
import BreadCrumb from '../../modules/commoncomponent/breadcrumb/bread_crumb';
import { containerConstantsService } from '../../utils/containerconstants/ContainerConstants';
import { Card, Row, Col, Space, Table, Button, Spin, Input } from 'antd';
import AwbGenerationSettingStyle from './AWBGenerationSettingsStyle.js';
import AWBGenerationFormModal from './AWBGenerationFormModal';
import MdEdit from '../commoncomponent/CustomIcons/MdEdit';
import { PAGE_SIZE, STATUS, AWB_DEFAULT_SUB_CARD_HEADING, AWB_FORM_AND_CARD_TYPES, DATA_INDEX, FORM_AND_CARD_ELEMENTS_CONST, FORM_TYPES, OPERATIONS, AWB_STRING_CONSTANTS } from '../../utils/constants';
import { isEmpty, isEqual, toLower, upperFirst } from 'lodash';
import AWBEmptyDataView from './AWBEmptyDataView';
import AWBAddUploadModal from './AWBAddUploadModal';
import { Popover } from 'antd';
import MoreOutlined from '../../modules/commoncomponent/CustomIcons/MoreOutlined';
import { deleteAWBPartyConf, fetchAWBDefaultDetails, fetchAllPartyMaster, searchAWBPartyListByPartyCode } from '../APIConfig/AWBGenerationAction';
import { notifyResponseMessage } from '../commoncomponent/NotificationComponent/notifyResponseMessage';
import CustomPagination from '../commoncomponent/CustomPagination/CustomPagination'
import { SearchOutlined } from '@ant-design/icons';
import { useStore } from '../hook-store/store';
import { getBasePath } from '../commoncomponent/BasePath';

const containerConstants = containerConstantsService.getInstance();

const AWBGenerationSettings = (props) => {
  const [showFormModalDialog, setShowFormModalDialog] = useState({ visible: false, okText: '', title: '', operation: '', data: {} });
  const [showDeleteModalDialog, setShowDeleteModalDialog] = useState({ visible: false, okText: '', title: '' });
  const [showCustomizedFormModalDialog, setShowCustomizedFormModalDialog] = useState({ visible: false, okText: '', title: '' });
  const [awbDefaultData, setAWBDefaultData] = useState({});
  const [showModalDialogAddUpload, setShowModalDialogAddUpload] = useState(false);
  const [awbTableData, setAWBTableData] = useState([]);
  const [awbPartyCodeList, setAWBPartyCodeList] = useState([]);
  const [showPopover, setShowPopover] = useState({ visible: false, key: null });
  const [showLoading, setShowLoading] = useState(false);
  const [pageDetail, setPageDetail] = useState({ current: 0, pageSize: 10 });
  const [paginationDetails, setPaginationDetails] = useState({ totalElements: 0, numberOfElements: 0, pageSizeText: PAGE_SIZE.PAGE_10 });
  const [callOnlyAwbListAPI, setCallOnlyAwbListAPI] = useState(false);
  const [allPartyMasterCodeWithNameMaps, setAllPartyMasterCodeWithNameMaps] = useState({});
  const [allPartyNameWithMasterCodeMaps, setAllPartyNameWithMasterCodeMaps] = useState({});
  const [emptySearchResult, setEmptySearchResult] = useState(false);
  const [searchfilters, setSearchfilters] = useState('');
  const [searchInput, setSearchInput] = useState();
  const [fromSearch, setFromSearch] = useState(false);
  const store = useStore(true)[0];
  const searchedColumn  = useState()[0];
  const searchText = useState()[0];
  const [ basePath, setBasePath ]  = useState(''); 

  const openFormModal = () => {
    // isEmpty(awbTableData) ?
    setShowModalDialogAddUpload(true);
    // setShowCustomizedFormModalDialog({
    //   visible: true,
    //   okText: containerConstants.formatString(containerConstants.ADD),
    //   title: containerConstants.formatString(containerConstants.ADD_AWB)
    // });
  }

  const awbPopoverClasses = 'awb-popover-icon flex align-center justify-center pointer mr10';

  const urlList =
    [
      {
        url: basePath + '/v2/label_generation/v2/settings',
        heading: containerConstants.formatString(containerConstants.SETTINGS),
      },
      {
        url: basePath + '/v2/label_generation/settings',
        heading: containerConstants.formatString(containerConstants.ADD_ORDER_AND_GENERATE_LABEL)
      },
      {
        url: basePath + '/v2/label_generation/shipment_no_generation',
        heading: containerConstants.formatString(containerConstants.AWB_GENERATION)
      }
    ];

  const urlListForNewSetting =
    [
      {
        url: '/v2/new_settings/label_generation/settings',
        heading: containerConstants.formatString(containerConstants.ADD_ORDER_AND_GENERATE_LABEL)
      },
      {
        url: '/v2/new_settings/label_generation/shipment_no_generation',
        heading: containerConstants.formatString(containerConstants.AWB_GENERATION)
      }
    ];

  const deleteTableRow = (id) => {
    deleteAWBPartyConf(id)
      .then(response => {
        if (response.status === 200) {
          if (response.data.status === "Success") {
            setFromSearch(false);
            notifyResponseMessage(STATUS.SUCCESS, response.data.message);
            setCallOnlyAwbListAPI(true);
            getInitializeLocalState();

          } else {
            notifyResponseMessage(STATUS.ERROR, response.data.message)
          }

        }
      })
      .catch(error => {

      });
  }

  const editTableRow = (dataObject) => {
    setShowCustomizedFormModalDialog({
      visible: true,
      okText: containerConstants.formatString(containerConstants.SAVE),
      title: containerConstants.formatString(containerConstants.EDIT_AWB),
      operation: OPERATIONS.EDIT,
      data: dataObject
    });
  }

  const editDefaultDetails = () => {
    setShowFormModalDialog({
      visible: true,
      okText: containerConstants.formatString(containerConstants.SAVE),
      title: containerConstants.formatString(containerConstants.EDIT_DEFAULT_AWB),
      operation: OPERATIONS.EDIT,
      data: awbDefaultData
    })
  }

  useEffect(() => {
    setBasePath(getBasePath(props, store));

    document.title = containerConstants.formatString(containerConstants.AWB_GENERATION);
    getInitializeLocalState();
  }, [pageDetail]);

  const getInitializeLocalState = async () => {
    setShowLoading(true);
    const awbDefaultDetails = {}
    let allPartyMasterCodeWithNameMap = {}
    let allPartyNameWithMasterCodeMap = {}

    try {
      if (!callOnlyAwbListAPI) {
        const awbDefaultDetailsResponse = await fetchAWBDefaultDetails();
        if (awbDefaultDetailsResponse.status === 200) {
          setShowLoading(false);
          const awbDefaultDetailsData = awbDefaultDetailsResponse.data?.data;
          if (awbDefaultDetailsData !== null) {
            const subCardKeys = Object.values(AWB_FORM_AND_CARD_TYPES);
            subCardKeys.forEach(subCardKey => {
              awbDefaultDetails[subCardKey] = {}
              FORM_AND_CARD_ELEMENTS_CONST[subCardKey].forEach(cardDetail => {
                awbDefaultDetailsData[cardDetail.name] !== null && awbDefaultDetailsData[cardDetail.name] !== undefined && (awbDefaultDetails[subCardKey][cardDetail.name] = awbDefaultDetailsData[cardDetail.name])
              });
            })
            awbDefaultDetails['id'] = awbDefaultDetailsData?.id;
            setAWBDefaultData(awbDefaultDetails);
          }
        } else {
          setShowLoading(false);
        }

        const allPartyMasterResponse = await fetchAllPartyMaster();
        if (allPartyMasterResponse.status === 200) {

          const allPartyMasterList = allPartyMasterResponse.data?.data;
          allPartyMasterCodeWithNameMap = allPartyMasterList.reduce((previousMap, partyMasterObj) => { previousMap[partyMasterObj.merchantCode] = partyMasterObj.name; return previousMap }, {})
          allPartyNameWithMasterCodeMap = allPartyMasterList.reduce((previousMap, partyMasterObj) => {
            previousMap[partyMasterObj.name] = previousMap[partyMasterObj.name] ? previousMap[partyMasterObj.name] + '&&##&&' + partyMasterObj.merchantCode : partyMasterObj.merchantCode;
            return previousMap
          }, {})
          setAllPartyNameWithMasterCodeMaps(allPartyNameWithMasterCodeMap);
          setAllPartyMasterCodeWithNameMaps(allPartyMasterCodeWithNameMap);
        }
      }

      searchList('', Object.keys(awbDefaultDetails).length > 0 ? awbDefaultDetails : awbDefaultData
        , Object.keys(allPartyMasterCodeWithNameMap).length > 0 ? allPartyMasterCodeWithNameMap : allPartyMasterCodeWithNameMaps);
    } catch (error) {

    }
  }

  const searchList = async (partycodes, awbDefaultDetailsParam, allPartyMasterCodeWithNameMapParam) => {
    await searchAWBPartyListByPartyCode(partycodes, pageDetail.current, pageDetail.pageSize)
      .then(response => {
        if (response.status === 200) {
          if (response.data && response.data.data) {
            const awbPartyMasterDtoList = response.data.data.content;
            if (!isEmpty(awbPartyMasterDtoList)) {
              const awbTableDataList = awbPartyMasterDtoList.map(awbDataObj => {
                const subCardKey = toLower(awbDataObj[DATA_INDEX.SELECTED_FORM]);
                let { awbType, awbGenerationType } = awbDataObj;
                awbType = upperFirst(toLower(awbType));
                awbGenerationType = subCardKey;
                const defaultData = isEqual(awbType, FORM_TYPES[0]) ? awbDefaultDetailsParam[subCardKey] : {};
                const subCard = { ...awbDataObj, ...defaultData, ...{ awbType, awbGenerationType } }
                return { ...subCard, [DATA_INDEX.PARTY_NAME]: allPartyMasterCodeWithNameMapParam[awbDataObj.partyCode] };
              });
              setAWBTableData(awbTableDataList);
              setPaginationDetails({
                totalElements: response.data.data.totalElements,
                numberOfElements: response.data.data.numberOfElements,
                pageSizeText: paginationDetails.pageSizeText
              });
              setFromSearch(false);
              setEmptySearchResult(false);
            } else {
              if (response.data.data.totalElements > 0 && pageDetail.current > 0) {
                setFromSearch(false);
                setEmptySearchResult(false);
                setPageDetail({ current: pageDetail.current - 1, pageSize: pageDetail.pageSize });
              } else {

                setAWBTableData([]);
                setPaginationDetails({
                  totalElements: 0,
                  numberOfElements: 0,
                  pageSizeText: paginationDetails.pageSizeText
                });
              }
            }
            setShowLoading(false);
          }

        }
      });
  }

  const getColDefaultDetailsJsx = (heading, dataIndex, spanSize, subCardName) => {
    return (
      <Col span={spanSize}><Space direction='vertical' size={2} ><span style={{ fontSize: 12 }}>{heading}</span><p>{awbDefaultData[subCardName][dataIndex] !== null && awbDefaultData[subCardName][dataIndex] !== undefined ? (awbDefaultData[subCardName][dataIndex]).toString() : awbDefaultData[subCardName][dataIndex]}</p></Space></Col>
    )
  }

  const getSubDefaultDetailsCardJsx = (subCardName) => {
    return (

      <Card className='fs12 lh18 border-none' bodyStyle={{ color: '#727272', fontSize: 'small' }} title={AWB_DEFAULT_SUB_CARD_HEADING[subCardName]}>
        <Row justify='space-between'>
          {FORM_AND_CARD_ELEMENTS_CONST[subCardName].map(data => getColDefaultDetailsJsx(data.label, data.name, data.spanSize, subCardName))}
        </Row>
      </Card>
    );
  }

  const CustomCell = ({ children, record, ...restProps }) => {
    return (
      <td {...restProps}>
        {record ?
          (<div className='flex align-center'>
            <Popover
              overlayClassName='awb-gen-table-popover'
              // visible={record?.id === showPopover.key && showPopover.visible}
              // onVisibleChange={(visible) => setShowPopover(visible ? { visible: visible, key: record.id } : {})}
              id='awb-table-popover'
              placement="bottomLeft"
              trigger="click"
              content={
                <div className='fs14 lh22'>
                  <p className='mb10 pointer' onClick={() => { editTableRow(record); setShowPopover({ visible: false, key: null }) }}>
                    {containerConstants.formatString(containerConstants.EDIT)}
                  </p>
                  <p className='pointer' onClick={() => {
                    setShowDeleteModalDialog({
                      visible: true,
                      okText: containerConstants.formatString(containerConstants.DELETE),
                      title: containerConstants.formatString(containerConstants.DELETE) + '?',
                      description: containerConstants.formatString(containerConstants.DELETE_DESCRIPTION),
                      rowId: record.id
                    });
                    setShowPopover({ visible: false, key: null });
                  }}>
                    {containerConstants.formatString(containerConstants.DELETE)}
                  </p>
                </div>}
            >
              <div className={((record?.id === showPopover.key) ? awbPopoverClasses.concat(' ', 'selected bg-primary') : awbPopoverClasses)}>
                <MoreOutlined color={(record?.id === showPopover.key) ? '#FFFFFF' : '#323232'} />
              </div>
            </Popover>
            <span className='font-family-weight-normal fs12 lh18'>{children[1]}</span>
          </div>) : children[1]}
      </td>
    );
  }

  const handlePageChange = (val) => {
    setCallOnlyAwbListAPI(true);
    setPageDetail({ current: val - 1, pageSize: pageDetail.pageSize });
  }

  const handlePgaeSizeChange = (val) => {
    setCallOnlyAwbListAPI(true);
    let pageSize = 10;
    let pageSizeTxt = PAGE_SIZE.PAGE_10;
    switch (val) {
      case PAGE_SIZE.PAGE_10:
        pageSize = 10;
        pageSizeTxt = PAGE_SIZE.PAGE_10;
        break;
      case PAGE_SIZE.PAGE_20:
        pageSize = 20;
        pageSizeTxt = PAGE_SIZE.PAGE_20;
        break;
      case PAGE_SIZE.PAGE_50:
        pageSize = 50;
        pageSizeTxt = PAGE_SIZE.PAGE_50;
        break;
      case PAGE_SIZE.PAGE_100:
        pageSize = 100;
        pageSizeTxt = PAGE_SIZE.PAGE_100;
        break;
      default:
        break;
    }

    setPaginationDetails({
      totalElements: paginationDetails.totalElements,
      numberOfElements: paginationDetails.numberOfElements,
      pageSizeText: pageSizeTxt
    });
    setPageDetail({ current: 0, pageSize: pageSize });
  }

  const handleSearch = (selectedKeys, confirm, dataIndex) => {
    let partycodes = '';
    Object.keys(allPartyNameWithMasterCodeMaps).map((key) => {
      if (key.toLowerCase().includes(searchfilters.toLowerCase())) {
        partycodes = partycodes === '' ? allPartyNameWithMasterCodeMaps[key] : partycodes + '&&##&&' + allPartyNameWithMasterCodeMaps[key];
      }
    });
    setEmptySearchResult(true);

    if (searchfilters !== '' && partycodes === '') {
      partycodes = searchfilters;
    }
    setFromSearch(true);
    searchList(partycodes, awbDefaultData, allPartyMasterCodeWithNameMaps);
  };

  const handleReset = (dataIndex) => {
    setSearchfilters('');
    searchList('', awbDefaultData, allPartyMasterCodeWithNameMaps);
  };

  const getColumnSearchProps = (dataValue, dataIndex) => ({

    filterDropdown: ({ setSelectedKeys, selectedKeys, confirm, clearFilters }) => (
      <div style={{ padding: 8 }}>
        <Input
          placeholder={`Search ${dataValue}`}
          value={searchfilters}
          onChange={e => {
            setSearchfilters(e.target.value);
            return e.target.value;

          }}
          onPressEnter={() => handleSearch(selectedKeys, confirm, dataIndex)}
          style={{ width: 188, marginBottom: 8, display: 'block' }}
        />
        <Space>
          <Button
            type="primary"
            onClick={() => handleSearch(selectedKeys, confirm, dataIndex)}
            icon={<SearchOutlined />}
            size="small"
            style={{ width: 90 }}
          >
            Search
          </Button>
          <Button onClick={() => handleReset(dataIndex)} size="small" style={{ width: 90 }}>
            Reset
          </Button>

        </Space>
      </div>
    ),
    filterIcon: filtered => <SearchOutlined style={{ fontSize: '14px', marginRight: '10px', color: '#727272' }} />,
    onFilter: (value, record) => record[dataIndex]
      ? record[dataIndex].toString().toLowerCase().includes(value.toLowerCase())
      : ''
    ,
    onFilterDropdownVisibleChange: visible => {
      if (visible) {
        setTimeout(() => searchInput && searchInput.select(), 100);
      }
    },
    render: text =>
      searchedColumn === dataIndex ?
        searchText :
        text

  });


  const AWB_GENERATION_TABLE_COLUMN = [
    {
      title: <div className='font-family-weight-500 lh18 text-center fs10 text-upper'>{AWB_STRING_CONSTANTS.PARTY_NAME}</div>,
      className: 'border-right AWB_SEARCH_FILTER',
      children: [
        {
          fixed: 'left',
          dataIndex: DATA_INDEX.PARTY_NAME, width: 120,
          className: 'border-right sub-header-bg',
          onCell: (record, rowIndex) => ({ record, rowIndex }),

        },
      ],
      ...getColumnSearchProps(DATA_INDEX.PARTY_NAME, DATA_INDEX.PARTY_NAME),

    },
    {
      title: <div className='font-family-weight-500 lh18 text-center fs10 text-upper'>{AWB_STRING_CONSTANTS.PARTY_CODE}</div>,
      className: 'border-right',
      children: [
        {
          dataIndex: DATA_INDEX.PARTY_CODE, width: 120,
          className: 'border-right sub-header-bg',
          render: text => <div className='font-family-weight-normal fs12 lh18'>{text}</div>
        },
      ]
    },
    {
      title: <div className='font-family-weight-500 lh18 text-center fs10 text-upper'>{AWB_STRING_CONSTANTS.TYPE}</div>,
      className: 'border-right',
      children: [
        {
          dataIndex: DATA_INDEX.TYPE, width: 120,
          className: 'border-right sub-header-bg',
          render: text => <div className='font-family-weight-normal fs12 lh18'>{text}</div>
        },
      ]
    },
    {
      title: <div className='font-family-weight-500 lh18 text-center fs10 text-upper'>{AWB_STRING_CONSTANTS.SERIES}</div>,
      className: 'border-right',
      render: text => <div className='font-family-weight-normal fs12 lh18'>{text}</div>,
      children: [
        {
          title: <div className='font-family-weight-normal fs11 lh18 text-center'>{AWB_STRING_CONSTANTS.START_WITH}</div>, dataIndex: DATA_INDEX.START_WITH, width: 140,
          className: 'sub-header-bg',
          render: text => <div className='font-family-weight-normal fs12 lh18'>{text !== null && text !== undefined && text !== '' ? text : '-'}</div>
        },
        {
          title: <div className='font-family-weight-normal fs11 lh18 text-center'>{AWB_STRING_CONSTANTS.ENDS_WITH}</div>, dataIndex: DATA_INDEX.ENDS_WITH, width: 140,
          className: 'sub-header-bg',
          render: text => <div className='font-family-weight-normal fs12 lh18'>{text !== null && text !== undefined && text !== '' ? text : '-'}</div>
        },
        {
          title: <div className='font-family-weight-normal fs11 lh18 text-center'>{AWB_STRING_CONSTANTS.START_RANGE}</div>, dataIndex: DATA_INDEX.START_RANGE, width: 140,
          className: 'sub-header-bg',
          render: text => <div className='font-family-weight-normal fs12 lh18'>{text !== null && text !== undefined ? text : '-'}</div>
        },
        {
          title: <div className='font-family-weight-normal fs11 lh18 text-center'>{AWB_STRING_CONSTANTS.END_RANGE}</div>, dataIndex: DATA_INDEX.END_RANGE, width: 140,
          className: 'sub-header-bg',
          render: text => <div className='font-family-weight-normal fs12 lh18'>{text !== null && text !== undefined ? text : '-'}</div>
        },
        {
          title: <div className='font-family-weight-normal fs11 lh18 text-center'>{AWB_STRING_CONSTANTS.RUNNING_NUMBER}</div>, dataIndex: DATA_INDEX.RUNNING_NUMBER, width: 140,
          className: 'border-right sub-header-bg',
          render: text => <div className='font-family-weight-normal fs12 lh18'>{text !== null && text !== undefined ? text : '-'}</div>
        },
        {
          title: <div className='font-family-weight-normal fs11 lh18 text-center'>{AWB_STRING_CONSTANTS.IS_LEADING_ZERO_APPENDED}</div>, dataIndex: DATA_INDEX.IS_LEADING_ZERO_APPENDED, width: 140,
          className: 'border-right sub-header-bg',
          render: text => <div className='font-family-weight-normal fs12 lh18'>{text !== null && text !== undefined ? text.toString() : '-'}</div>
        },
      ]
    },
    {
      title: <div className='font-family-weight-500 lh18 text-center fs10 text-upper'>{AWB_STRING_CONSTANTS.CHECKSUM}</div>,
      className: 'border-right',
      render: text => <div className='font-family-weight-normal fs12 lh18'>{text}</div>,
      children: [
        {
          title: <div className='font-family-weight-normal fs11 lh18 text-center'>{AWB_STRING_CONSTANTS.LENGTH_OF_AWB}</div>, dataIndex: DATA_INDEX.LENGTH_OF_AWB, width: 140,
          className: 'sub-header-bg',
          render: text => <div className='font-family-weight-normal fs12 lh18'>{text !== null && text !== undefined ? text : '-'}</div>
        },
        {
          title: <div className='font-family-weight-normal fs11 lh18 text-center'>{AWB_STRING_CONSTANTS.CHECK_DIGIT}</div>, dataIndex: DATA_INDEX.CHECK_DIGIT, width: 140,
          className: 'sub-header-bg',
          render: text => <div className='font-family-weight-normal fs12 lh18'>{text !== null && text !== undefined ? text : '-'}</div>
        },
        {
          title: <div className='font-family-weight-normal fs11 lh18 text-center'>{AWB_STRING_CONSTANTS.SNO_START_POSITION}</div>, dataIndex: DATA_INDEX.SNO_START_POSITION, width: 140,
          className: 'sub-header-bg',
          render: text => <div className='font-family-weight-normal fs12 lh18'>{text !== null && text !== undefined ? text : '-'}</div>
        },
        {
          title: <div className='font-family-weight-normal fs11 lh18 text-center'>{AWB_STRING_CONSTANTS.SNO_END_POSITION}</div>, dataIndex: DATA_INDEX.SNO_END_POSITION, width: 140,
          className: 'sub-header-bg',
          render: text => <div className='font-family-weight-normal fs12 lh18'>{text !== null && text !== undefined ? text : '-'}</div>
        },
        {
          title: <div className='font-family-weight-normal fs11 lh18 text-center'>{AWB_STRING_CONSTANTS.MOD_BY}</div>, dataIndex: DATA_INDEX.MOD_BY, width: 140,
          className: 'border-right sub-header-bg',
          render: text => <div className='font-family-weight-normal fs12 lh18'>{text !== null && text !== undefined ? text : '-'}</div>
        },
      ]
    },
    {
      title: <div className='font-family-weight-500 lh18 text-center fs10 text-upper'>{AWB_STRING_CONSTANTS.EXTERNAL_SYSTEM}</div>,
      className: 'border-right',
      render: text => <div className='font-family-weight-normal fs12 lh18'>{text}</div>,
      children: [
        {
          title: <div className='font-family-weight-normal fs11 lh18 text-center'>{AWB_STRING_CONSTANTS.END_POINT}</div>, dataIndex: DATA_INDEX.END_POINT, width: 140,
          className: 'sub-header-bg',
          render: text => <div className='font-family-weight-normal fs12 lh18'>{text ? text : '-'}</div>
        },
        {
          title: <div className='font-family-weight-normal fs11 lh18 text-center'>{AWB_STRING_CONSTANTS.TIMEOUT_SECONDS}</div>, dataIndex: DATA_INDEX.TIMEOUT_SECONDS, width: 140,
          className: 'sub-header-bg',
          render: text => <div className='font-family-weight-normal fs12 lh18'>{text ? text : '-'}</div>
        },
        {
          title: <div className='font-family-weight-normal fs11 lh18 text-center'>{AWB_STRING_CONSTANTS.NO_OF_RE_ATTEMPTS}</div>, dataIndex: DATA_INDEX.NO_OF_RE_ATTEMPTS, width: 140,
          className: 'border-right sub-header-bg',
          render: text => <div className='font-family-weight-normal fs12 lh18'>{text ? text : '-'}</div>
        },
      ]
    },
    {
      title: <div className='font-family-weight-500 lh18 text-center fs10 text-upper'>{AWB_STRING_CONSTANTS.REGEX}</div>,
      render: text => <div className='font-family-weight-normal fs12 lh18'>{text}</div>,
      children: [
        {
          title: <div className='font-family-weight-normal fs11 lh18 text-center'>{AWB_STRING_CONSTANTS.STANDARD}</div>, dataIndex: DATA_INDEX.STANDARD, width: 140,
          className: 'sub-header-bg',
          render: text => <div className='font-family-weight-normal fs12 lh18'>{text ? text : '-'}</div>
        },
      ]
    },
    {
      title: <div className='font-family-weight-500 lh18 text-center fs10 text-upper'>{AWB_STRING_CONSTANTS.HYBRID}</div>,
      className: 'border-right',
      render: text => <div className='font-family-weight-normal fs12 lh18'>{text}</div>,
      children: [
        {
          title: <div className='font-family-weight-normal fs11 lh18 text-center'>{AWB_STRING_CONSTANTS.START_WITH}</div>, dataIndex: DATA_INDEX.START_WITH_HYBRID, width: 140,
          className: 'sub-header-bg',
          render: text => <div className='font-family-weight-normal fs12 lh18'>{text !== null && text !== undefined && text !== '' ? text : '-'}</div>
        },
        {
          title: <div className='font-family-weight-normal fs11 lh18 text-center'>{AWB_STRING_CONSTANTS.ENDS_WITH}</div>, dataIndex: DATA_INDEX.ENDS_WITH_HYBRID, width: 140,
          className: 'sub-header-bg',
          render: text => <div className='font-family-weight-normal fs12 lh18'>{text !== null && text !== undefined && text !== '' ? text : '-'}</div>
        },
        {
          title: <div className='font-family-weight-normal fs11 lh18 text-center'>{AWB_STRING_CONSTANTS.START_RANGE}</div>, dataIndex: DATA_INDEX.START_RANGE_HYBRID, width: 140,
          className: 'sub-header-bg',
          render: text => <div className='font-family-weight-normal fs12 lh18'>{text !== null && text !== undefined ? text : '-'}</div>
        },
        {
          title: <div className='font-family-weight-normal fs11 lh18 text-center'>{AWB_STRING_CONSTANTS.END_RANGE}</div>, dataIndex: DATA_INDEX.END_RANGE_HYBRID, width: 140,
          className: 'sub-header-bg',
          render: text => <div className='font-family-weight-normal fs12 lh18'>{text !== null && text !== undefined ? text : '-'}</div>
        },
        {
          title: <div className='font-family-weight-normal fs11 lh18 text-center'>{AWB_STRING_CONSTANTS.RUNNING_NUMBER}</div>, dataIndex: DATA_INDEX.RUNNING_NUMBER_HYBRID, width: 140,
          className: 'border-right sub-header-bg',
          render: text => <div className='font-family-weight-normal fs12 lh18'>{text !== null && text !== undefined ? text : '-'}</div>
        },
        {
          title: <div className='font-family-weight-normal fs11 lh18 text-center'>{AWB_STRING_CONSTANTS.MOD_BY}</div>, dataIndex: DATA_INDEX.MOD_BY_HYBRID, width: 140,
          className: 'border-right sub-header-bg',
          render: text => <div className='font-family-weight-normal fs12 lh18'>{text !== null && text !== undefined ? text : '-'}</div>
        },
        {
          title: <div className='font-family-weight-normal fs11 lh18 text-center'>{AWB_STRING_CONSTANTS.IS_LEADING_ZERO_APPENDED}</div>, dataIndex: DATA_INDEX.IS_LEADING_ZERO_APPENDED_HYBRID, width: 140,
          className: 'border-right sub-header-bg',
          render: text => <div className='font-family-weight-normal fs12 lh18'>{text !== null && text !== undefined ? text.toString() : '-'}</div>
        },
      ]
    },
    {
      title: <div className='font-family-weight-500 lh18 text-center fs10 text-upper'>{AWB_STRING_CONSTANTS.CHECK_DIGIT}</div>,
      className: 'border-right',
      render: text => <div className='font-family-weight-normal fs12 lh18'>{text}</div>,
      children: [
        {
          title: <div className='font-family-weight-normal fs11 lh18 text-center'>{AWB_STRING_CONSTANTS.START_WITH}</div>, dataIndex: DATA_INDEX.START_WITH_CHECK_DIGIT, width: 140,
          className: 'sub-header-bg',
          render: text => <div className='font-family-weight-normal fs12 lh18'>{text !== null && text !== undefined && text !== '' ? text : '-'}</div>
        },
        {
          title: <div className='font-family-weight-normal fs11 lh18 text-center'>{AWB_STRING_CONSTANTS.ENDS_WITH}</div>, dataIndex: DATA_INDEX.ENDS_WITH_CHECK_DIGIT, width: 140,
          className: 'sub-header-bg',
          render: text => <div className='font-family-weight-normal fs12 lh18'>{text !== null && text !== undefined && text !== '' ? text : '-'}</div>
        },
        {
          title: <div className='font-family-weight-normal fs11 lh18 text-center'>{AWB_STRING_CONSTANTS.START_RANGE}</div>, dataIndex: DATA_INDEX.START_RANGE_CHECK_DIGIT, width: 140,
          className: 'sub-header-bg',
          render: text => <div className='font-family-weight-normal fs12 lh18'>{text !== null && text !== undefined ? text : '-'}</div>
        },
        {
          title: <div className='font-family-weight-normal fs11 lh18 text-center'>{AWB_STRING_CONSTANTS.END_RANGE}</div>, dataIndex: DATA_INDEX.END_RANGE_CHECK_DIGIT, width: 140,
          className: 'sub-header-bg',
          render: text => <div className='font-family-weight-normal fs12 lh18'>{text !== null && text !== undefined ? text : '-'}</div>
        },
        {
          title: <div className='font-family-weight-normal fs11 lh18 text-center'>{AWB_STRING_CONSTANTS.RUNNING_NUMBER}</div>, dataIndex: DATA_INDEX.RUNNING_NUMBER_CHECK_DIGIT, width: 140,
          className: 'border-right sub-header-bg',
          render: text => <div className='font-family-weight-normal fs12 lh18'>{text !== null && text !== undefined ? text : '-'}</div>
        },
        {
          title: <div className='font-family-weight-normal fs11 lh18 text-center'>{AWB_STRING_CONSTANTS.BASE}</div>, dataIndex: DATA_INDEX.BASE_CHECK_DIGIT, width: 140,
          className: 'border-right sub-header-bg',
          render: text => <div className='font-family-weight-normal fs12 lh18'>{text !== null && text !== undefined ? text : '-'}</div>
        },
        {
          title: <div className='font-family-weight-normal fs11 lh18 text-center'>{AWB_STRING_CONSTANTS.IS_LEADING_ZERO_APPENDED}</div>, dataIndex: DATA_INDEX.IS_LEADING_ZERO_APPENDED_CHECK_DIGIT, width: 140,
          className: 'border-right sub-header-bg',
          render: text => <div className='font-family-weight-normal fs12 lh18'>{text !== null && text !== undefined ? text.toString() : '-'}</div>
        },
      ]
    }
  ];

  return (
    <div>
      <AwbGenerationSettingStyle />
      <BreadCrumb
        urlList={store.fromNewSetting ? urlListForNewSetting : urlList}
        rightItem={
          (!isEmpty(awbDefaultData) || !isEmpty(awbTableData) || fromSearch) &&
          <Button
            style={{ display: 'flex', height: '24px', color: '#FFFFFF', padding: '0 8px' }}
            type="primary"
            onClick={openFormModal}
          >
            {containerConstants.formatString(containerConstants.ADD_AWB)}
          </Button>
        }
      // <Button
      //     className='fw500'
      //     style={{ display: 'flex', height: '24px', padding: '0 8px', borderRadius: '4px' }}
      //     type="primary"
      //     icon={<PlusOutlined style={{ display: 'flex', alignSelf: 'center', fontSize: '10px' }} />}
      //     onClick={() => setShowModalDialog({
      //         visible: true,
      //         title: containerConstants.formatString(containerConstants.CHOOSE_TEMPLATE),
      //         modalType: TEMPLATE_MODAL_TYPE.CHOOSE_TEMPLATE
      //     })}
      // >
      //     {containerConstants.formatString(containerConstants.CREATE_TEMPLATE)}
      // </Button> }

      />


      <Spin spinning={showLoading}>

        {
          ((!isEmpty(awbDefaultData) && isEmpty(awbTableData)) || (!isEmpty(awbDefaultData) && !isEmpty(awbTableData)) || (isEmpty(awbDefaultData) && !isEmpty(awbTableData)) || (fromSearch)) &&

          <Card visible={false} id='awb-default-details' className='m16 bg-transparent'
            headStyle={{ marginBottom: '4px' }}
            bodyStyle={{ padding: '12px 16px', border: '1px solid #DDDDDD', boxSizing: 'border-box', borderRadius: '4px', background: '#FFFFFF' }}
            title={containerConstants.formatString(containerConstants.AWB_DEFAULT_DETAILS)}
            extra={!isEmpty(awbDefaultData) &&
              <div onClick={editDefaultDetails}>
                <MdEdit size={'18px'} />
              </div>}
          >
            {!isEmpty(awbDefaultData) ?
              <div>
                <Row className='mb12'>
                  <Col span={14}>
                    {getSubDefaultDetailsCardJsx(AWB_FORM_AND_CARD_TYPES.SERIES)}
                  </Col>
                  <Col push={1} span={9}>
                    {getSubDefaultDetailsCardJsx(AWB_FORM_AND_CARD_TYPES.EXTERNAL_SYSTEM)}
                  </Col>
                </Row>
                <Row>
                  <Col span={14}>
                    {getSubDefaultDetailsCardJsx(AWB_FORM_AND_CARD_TYPES.CHECKSUM)}
                  </Col>
                  <Col push={1} span={9}>
                    {getSubDefaultDetailsCardJsx(AWB_FORM_AND_CARD_TYPES.REGEX)}
                  </Col>
                </Row>
                <Row>
                  <Col span={14}>
                    {getSubDefaultDetailsCardJsx(AWB_FORM_AND_CARD_TYPES.HYBRID)}
                  </Col>
                </Row>
                <Row>
                  <Col span={14}>
                    {getSubDefaultDetailsCardJsx(AWB_FORM_AND_CARD_TYPES.CHECK_DIGIT)}
                  </Col>
                </Row>
              </div> :
              <AWBEmptyDataView
                heading={containerConstants.formatString(containerConstants.NO_DEFAULT_AWB_ADDED)}
                description={containerConstants.formatString(containerConstants.NO_DEFAULT_AWB_ADDED_DESCRIPTION)}
                {...{ showButtons: 'first', awbTableData, awbDefaultData, setShowFormModalDialog, setShowModalDialogAddUpload }}
              />
            }
          </Card>
        }

        <Card
          title={(!isEmpty(awbDefaultData) || !isEmpty(awbTableData)) && containerConstants.formatString(containerConstants.AWB_LIST)}
          id='awb-gen-card'
          className='m16 bg-transparent'
          style={{ zIndex: 0 }}
          headStyle={{ marginBottom: '4px' }}
          bodyStyle={{ padding: '16px', border: '1px solid #DDDDDD', boxSizing: 'border-box', borderRadius: '4px', background: '#FFFFFF' }}
        >
          {!isEmpty(awbTableData) || emptySearchResult ?
            <>
              <Table bordered={true}
                components={{
                  body: {
                    cell: CustomCell
                  }
                }}
                pagination={false}
                columns={AWB_GENERATION_TABLE_COLUMN}
                dataSource={awbTableData}
                scroll={{ x: 1300 }}
                size='middle'
              />
              <CustomPagination pageDetail={pageDetail} paginationDetails={paginationDetails} handlePageChange={handlePageChange} handlePgaeSizeChange={handlePgaeSizeChange} curentPageOption={paginationDetails.pageSizeText} />
            </>
            :
            <AWBEmptyDataView
              heading={containerConstants.formatString(containerConstants.AWB_NOT_FOUND)}
              description={containerConstants.formatString(containerConstants.AWB_NOT_FOUND_DESCRIPTION)}
              {...{ showButtons: (!isEmpty(awbDefaultData) || !isEmpty(awbTableData)) ? 'none' : 'both' }}
              {...{ awbTableData, awbDefaultData, setShowFormModalDialog, setShowModalDialogAddUpload }}
            />
          }
        </Card>
        {showModalDialogAddUpload && <AWBAddUploadModal reloadPage={getInitializeLocalState} {...{ showModalDialogAddUpload, setShowModalDialogAddUpload, setShowCustomizedFormModalDialog }} />}
        {(showCustomizedFormModalDialog.visible || showDeleteModalDialog.visible || showFormModalDialog.visible) && <AWBGenerationFormModal

          reloadPage={getInitializeLocalState}
          {...{
            awbPartyCodeList,
            setAWBPartyCodeList,
            setShowPopover,
            showPopover,
            deleteTableRow,
            awbTableData,
            setAWBTableData,
            awbDefaultData,
            setAWBDefaultData,
            showFormModalDialog,
            setShowFormModalDialog,
            showDeleteModalDialog,
            setShowDeleteModalDialog,
            showCustomizedFormModalDialog,
            setShowCustomizedFormModalDialog
          }}
        />
        }
      </Spin>
    </div>);
}

export default AWBGenerationSettings;
